// // This module implements a 16-bit register that loads new data on the falling edge of the clock when the load signal is low.
module reg16 (
  input clk,
  input load,
  input [15:0] data,
  output reg [15:0] q
);

  always @(posedge clk) begin
    if (load) begin
      q <= data;
    end
  end

endmodule
